<?php namespace App\Models\Inventory; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\SoftDeletes; use Illuminate\Database\Eloquent\Concerns\HasUuids; class StockItem extends Model { use SoftDeletes, HasUuids; protected $fillable=['*']; protected $casts = ['unit_cost' => 'decimal:2', 'reorder_level' => 'decimal:2']; public function group() { return $this->belongsTo(\App\Models\StockGroup::class); } public function ledgers() { return $this->hasMany(\App\Models\StockLedger::class, 'item_id'); } public function journals() { return $this->hasMany(\App\Models\StockJournal::class, 'item_id'); } public function getTotalStock() { return $this->ledgers->sum('quantity'); } }
